{
  "name": "GX Schedule - Ciputra Club",
  "description": "A comprehensive Group Fitness schedule application for club members and staff management.",
  "requestFramePermissions": [
    "notifications"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Role = 'USER' | 'MANAGER' | 'ADMIN';

export interface User {
  id: string;
  name: string;
  role: Role;
}

export interface ClassSession {
  id: string;
  dayIndex: number; // 0 = Mon, 6 = Sun
  time: string;
  className: string;
  instructor: string;
  color: string;
}

export const DAYS_OF_WEEK = [
  { short: 'THỨ 2', long: 'MONDAY' },
  { short: 'THỨ 3', long: 'TUESDAY' },
  { short: 'THỨ 4', long: 'WEDNESDAY' },
  { short: 'THỨ 5', long: 'THURSDAY' },
  { short: 'THỨ 6', long: 'FRIDAY' },
  { short: 'THỨ 7', long: 'SATURDAY' },
  { short: 'CN', long: 'SUNDAY' },
];

export const COLORS = {
  blue: 'bg-sky-400',
  green: 'bg-emerald-500',
  teal: 'bg-teal-500',
  orange: 'bg-orange-400',
  indigo: 'bg-indigo-400'
};

import React, { useState, useEffect } from 'react';
import { Role, User, ClassSession, DAYS_OF_WEEK } from './types';
import Header from './components/Header';
import ScheduleGrid from './components/ScheduleGrid';
import LoginSimulator from './components/LoginSimulator';
import AdminPanel from './components/AdminPanel';
import NotificationList from './components/NotificationList';

const DEFAULT_SCHEDULE: ClassSession[] = [
  { id: '1', dayIndex: 0, time: '7:30 - 8:30', className: 'MIX YOGA', instructor: 'ANJALI', color: 'bg-sky-400' },
  { id: '2', dayIndex: 4, time: '7:30 - 8:30', className: 'HATHA FLOW', instructor: 'TRUNG', color: 'bg-sky-400' },
  { id: '3', dayIndex: 0, time: '9:15 - 10:15', className: 'FLOW YOGA', instructor: 'VIKRAM', color: 'bg-sky-400' },
  { id: '4', dayIndex: 1, time: '9:15 - 10:15', className: 'HATHA YOGA', instructor: 'ANJALI', color: 'bg-sky-400' },
  { id: '5', dayIndex: 2, time: '8:45 - 9:45', className: 'TAICHI', instructor: 'TRƯỜNG', color: 'bg-emerald-600' },
  { id: '6', dayIndex: 3, time: '9:15 - 10:15', className: 'CORE & TWIST', instructor: 'TRUNG', color: 'bg-sky-400' },
  { id: '7', dayIndex: 4, time: '8:45 - 9:45', className: 'TAICHI', instructor: 'TRƯỜNG', color: 'bg-emerald-600' },
  { id: '8', dayIndex: 5, time: '9:00 - 10:00', className: 'STRETCHING YOGA', instructor: 'TRUNG', color: 'bg-sky-400' },
  { id: '9', dayIndex: 6, time: '8:45 - 9:45', className: 'TAICHI', instructor: 'TRƯỜNG', color: 'bg-emerald-600' },
];

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [schedule, setSchedule] = useState<ClassSession[]>([]);
  const [notifications, setNotifications] = useState<string[]>([]);
  const [managers, setManagers] = useState<User[]>([
    { id: 'm1', name: 'Manager 1', role: 'MANAGER' }
  ]);

  useEffect(() => {
    const saved = localStorage.getItem('gx_schedule');
    if (saved) {
      setSchedule(JSON.parse(saved));
    } else {
      setSchedule(DEFAULT_SCHEDULE);
    }
  }, []);

  const updateSchedule = (newSchedule: ClassSession[]) => {
    setSchedule(newSchedule);
    localStorage.setItem('gx_schedule', JSON.stringify(newSchedule));
    addNotification("Lịch tập vừa được cập nhật!");
  };

  const addNotification = (msg: string) => {
    setNotifications(prev => [msg, ...prev].slice(0, 5));
  };

  const addManager = (name: string) => {
    const newManager: User = { id: Date.now().toString(), name, role: 'MANAGER' };
    setManagers(prev => [...prev, newManager]);
    addNotification(`Đã thêm quản lý mới: ${name}`);
  };

  const removeManager = (id: string) => {
    setManagers(prev => prev.filter(m => m.id !== id));
    addNotification("Đã xóa một tài khoản quản lý.");
  };

  return (
    <div className="min-h-screen bg-slate-50">
      <Header />

      <main className="max-w-7xl mx-auto px-4 py-8">
        <div className="flex flex-col md:flex-row gap-6 mb-8">
          <div className="flex-1">
            <h2 className="text-3xl font-bold text-teal-800 mb-2 text-center uppercase">
              Lịch GX Tháng 1/2026 - Ciputra Club
            </h2>
            <div className="flex justify-center mb-6">
               <LoginSimulator onLogin={setCurrentUser} currentUser={currentUser} />
            </div>
          </div>

          <div className="md:w-64">
             <NotificationList notifications={notifications} />
          </div>
        </div>

        <ScheduleGrid 
          schedule={schedule} 
          role={currentUser?.role || 'USER'} 
          onUpdate={updateSchedule}
        />

        {(currentUser?.role === 'ADMIN' || currentUser?.role === 'MANAGER') && (
          <div className="mt-12 bg-white p-6 rounded-xl shadow-lg border border-teal-100">
            <h3 className="text-xl font-bold text-teal-900 mb-6 flex items-center gap-2">
              <span className="p-2 bg-teal-100 rounded-lg">⚙️</span>
              Bảng Điều Khiển Quản Trị
            </h3>
            <AdminPanel 
              role={currentUser.role}
              managers={managers}
              onAddManager={addManager}
              onRemoveManager={removeManager}
              onAddNotification={addNotification}
            />
          </div>
        )}

        <div className="mt-12 text-sm text-gray-500 border-t pt-4 italic">
          <p>Quý hội viên lưu ý:</p>
          <p>1. Vui lòng không sử dụng điện thoại trong lớp học/ Please do not use your phone in the classroom</p>
        </div>
      </main>
    </div>
  );
};

export default App;

import React from 'react';

