export default Header;

import React, { useState } from 'react';
import { ClassSession, DAYS_OF_WEEK, Role } from '../types';
import ClassModal from './ClassModal';

interface Props {
  schedule: ClassSession[];
  role: Role;
  onUpdate: (newSchedule: ClassSession[]) => void;
}

const ScheduleGrid: React.FC<Props> = ({ schedule, role, onUpdate }) => {
  const [editingSession, setEditingSession] = useState<ClassSession | null>(null);
  const isManagement = role === 'ADMIN' || role === 'MANAGER';

  const handleSave = (session: ClassSession) => {
    const exists = schedule.find(s => s.id === session.id);
    if (exists) {
      onUpdate(schedule.map(s => s.id === session.id ? session : s));
    } else {
      onUpdate([...schedule, { ...session, id: Date.now().toString() }]);
    }
    setEditingSession(null);
  };

  const handleDelete = (id: string) => {
    onUpdate(schedule.filter(s => s.id !== id));
    setEditingSession(null);
  };

  const getSessionsForDay = (dayIndex: number) => {
    return schedule
      .filter(s => s.dayIndex === dayIndex)
      .sort((a, b) => a.time.localeCompare(b.time));
  };

  return (
    <div className="overflow-x-auto rounded-lg shadow-xl bg-white border border-gray-200">
      <div className="min-w-[1000px] grid grid-cols-7 border-b-2 border-teal-900">
        {DAYS_OF_WEEK.map((day, idx) => (
          <div key={idx} className="bg-teal-900 text-white p-3 text-center border-r border-teal-800 last:border-0">
            <div className="text-xs font-bold text-red-300">{day.short} - {day.long}</div>
          </div>
        ))}
      </div>

      <div className="min-w-[1000px] grid grid-cols-7 divide-x divide-gray-200 bg-gray-50 min-h-[600px]">
        {DAYS_OF_WEEK.map((_, dayIdx) => {
          const sessions = getSessionsForDay(dayIdx);
          return (
            <div key={dayIdx} className="flex flex-col gap-2 p-2">
              {sessions.map(session => (
                <div 
                  key={session.id} 
                  onClick={() => isManagement && setEditingSession(session)}
                  className={`group relative flex flex-col border border-gray-300 shadow-sm overflow-hidden cursor-pointer transition-transform hover:scale-[1.02] ${isManagement ? 'hover:ring-2 ring-teal-500' : ''}`}
                >
                  <div className="bg-white text-center py-1 text-xs font-bold border-b border-gray-200">
                    {session.time}
                  </div>
                  <div className={`${session.color} text-white text-center py-2 px-1 text-[11px] font-bold h-12 flex items-center justify-center leading-tight uppercase`}>
                    {session.className}
                  </div>
                  <div className="bg-orange-200 text-teal-900 text-center py-1 text-[10px] font-bold uppercase tracking-wider">
                    {session.instructor}
                  </div>
                  {isManagement && (
                    <div className="absolute inset-0 bg-black/10 opacity-0 group-hover:opacity-100 flex items-center justify-center">
                      <span className="bg-white/90 text-teal-900 text-[10px] px-2 py-1 rounded font-bold shadow">EDIT</span>
                    </div>
                  )}
                </div>
              ))}
              {isManagement && (
                <button 
                  onClick={() => setEditingSession({ 
                    id: '', 
                    dayIndex: dayIdx, 
                    time: '09:00 - 10:00', 
                    className: 'NEW CLASS', 
                    instructor: 'TBA', 
                    color: 'bg-teal-500' 
                  })}
                  className="mt-2 border-2 border-dashed border-gray-300 rounded p-2 text-gray-400 hover:text-teal-600 hover:border-teal-400 transition-colors text-xs font-bold"
                >
                  + ADD
                </button>
              )}
            </div>
          );
        })}
      </div>

      {editingSession && (
        <ClassModal 
          session={editingSession} 
          onClose={() => setEditingSession(null)} 
          onSave={handleSave} 
          onDelete={handleDelete}
        />
      )}
    </div>
  );
};

export default ScheduleGrid;

import React, { useState } from 'react';
import { ClassSession, COLORS, DAYS_OF_WEEK } from '../types';

interface Props {
  session: ClassSession;
  onClose: () => void;
  onSave: (session: ClassSession) => void;
  onDelete: (id: string) => void;
}

const ClassModal: React.FC<Props> = ({ session, onClose, onSave, onDelete }) => {
  const [form, setForm] = useState<ClassSession>(session);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in duration-200">
        <div className="bg-teal-800 p-6 text-white flex justify-between items-center">
          <h3 className="text-xl font-bold">{session.id ? 'Chỉnh Sửa Lớp' : 'Thêm Lớp Mới'}</h3>
          <button onClick={onClose} className="text-white/70 hover:text-white transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <div className="p-6 space-y-4">
          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Thứ</label>
            <select 
              className="w-full border rounded-lg p-2 focus:ring-2 ring-teal-500 outline-none"
              value={form.dayIndex}
              onChange={e => setForm({...form, dayIndex: parseInt(e.target.value)})}
            >
              {DAYS_OF_WEEK.map((d, i) => (
                <option key={i} value={i}>{d.short} - {d.long}</option>
              ))}
            </select>
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Thời Gian</label>
            <input 
              type="text" 
              className="w-full border rounded-lg p-2 focus:ring-2 ring-teal-500 outline-none"
              placeholder="Ví dụ: 09:15 - 10:15"
              value={form.time}
              onChange={e => setForm({...form, time: e.target.value})}
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Tên Lớp</label>
            <input 
              type="text" 
              className="w-full border rounded-lg p-2 focus:ring-2 ring-teal-500 outline-none"
              value={form.className}
              onChange={e => setForm({...form, className: e.target.value.toUpperCase()})}
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-1">Giáo Viên</label>
            <input 
              type="text" 
              className="w-full border rounded-lg p-2 focus:ring-2 ring-teal-500 outline-none"
              value={form.instructor}
              onChange={e => setForm({...form, instructor: e.target.value.toUpperCase()})}
            />
          </div>

          <div>
            <label className="block text-sm font-semibold text-gray-700 mb-2">Màu Sắc</label>
            <div className="flex gap-3">
              {Object.entries(COLORS).map(([name, cls]) => (
                <button 
                  key={name}
                  onClick={() => setForm({...form, color: cls})}
                  className={`w-8 h-8 rounded-full border-2 ${cls} ${form.color === cls ? 'ring-2 ring-offset-2 ring-teal-600' : 'border-transparent'}`}
                />
              ))}
            </div>
          </div>
        </div>

        <div className="p-6 bg-gray-50 flex gap-3">
          <button 
            onClick={() => onSave(form)}
            className="flex-1 bg-teal-600 text-white font-bold py-3 rounded-lg hover:bg-teal-700 transition-colors shadow-lg"
          >
            LƯU THAY ĐỔI
          </button>
          {session.id && (
            <button 
              onClick={() => onDelete(session.id)}
              className="px-4 bg-red-100 text-red-600 font-bold rounded-lg hover:bg-red-200 transition-colors"
            >
              XÓA
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default ClassModal;

import React, { useState } from 'react';
import { User, Role } from '../types';

interface Props {
  role: Role;
  managers: User[];
  onAddManager: (name: string) => void;
  onRemoveManager: (id: string) => void;
  onAddNotification: (msg: string) => void;
}

const AdminPanel: React.FC<Props> = ({ role, managers, onAddManager, onRemoveManager, onAddNotification }) => {
  const [newManagerName, setNewManagerName] = useState('');
  const [broadcastMsg, setBroadcastMsg] = useState('');

  const handleBroadcast = () => {
    if (!broadcastMsg) return;
    onAddNotification(broadcastMsg);
    setBroadcastMsg('');
  };

  return (
    <div className="grid md:grid-cols-2 gap-8">
      {/* Notifications Management */}
      <div className="space-y-4">
        <h4 className="font-bold text-gray-700 flex items-center gap-2">
          <span>📢</span> Thông Báo Tới Hội Viên
        </h4>
        <div className="flex gap-2">
          <input 
            type="text"
            placeholder="Nội dung thông báo..."
            className="flex-1 border rounded-lg p-2 text-sm outline-none focus:ring-2 ring-teal-500"
            value={broadcastMsg}
            onChange={e => setBroadcastMsg(e.target.value)}
          />
          <button 
            onClick={handleBroadcast}
            className="bg-teal-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-teal-700"
          >
            GỬI
          </button>
        </div>
        <p className="text-xs text-gray-500">
          Thông báo này sẽ hiển thị ở góc trên màn hình cho tất cả người dùng.
        </p>
      </div>

      {/* Manager Management - ONLY FOR ADMIN */}
      <div className="space-y-4 border-l pl-8 border-gray-100">
        <h4 className="font-bold text-gray-700 flex items-center gap-2">
          <span>👤</span> Quản Lý Nhân Sự
        </h4>

        {role === 'ADMIN' ? (
          <>
            <div className="flex gap-2">
              <input 
                type="text"
                placeholder="Tên quản lý mới..."
                className="flex-1 border rounded-lg p-2 text-sm outline-none focus:ring-2 ring-teal-500"
                value={newManagerName}
                onChange={e => setNewManagerName(e.target.value)}
              />
              <button 
                onClick={() => {
                  if (newManagerName) {
                    onAddManager(newManagerName);
                    setNewManagerName('');
                  }
                }}
                className="bg-teal-900 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-black"
              >
                THÊM
              </button>
            </div>

            <div className="space-y-2 mt-4 max-h-40 overflow-y-auto">
              {managers.map(m => (
                <div key={m.id} className="flex items-center justify-between bg-gray-50 p-2 rounded-lg border">
                  <div>
                    <p className="text-sm font-bold text-gray-800">{m.name}</p>
                    <p className="text-[10px] text-gray-500 uppercase tracking-widest">{m.role}</p>
                  </div>
                  <button 
                    onClick={() => onRemoveManager(m.id)}
                    className="text-red-500 hover:text-red-700 p-1"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                    </svg>
                  </button>
                </div>
              ))}
            </div>
          </>
        ) : (
          <div className="bg-orange-50 p-4 rounded-lg border border-orange-200 flex items-start gap-3">
             <span className="text-orange-500 text-xl">⚠️</span>
             <p className="text-sm text-orange-800 leading-tight">
               Tài khoản <strong>MANAGER</strong> không có quyền quản lý người dùng khác. Vui lòng liên hệ <strong>ADMIN</strong> nếu cần hỗ trợ.
             </p>
          </div>
        )}
      </div>
    </div>
  );
};

export default AdminPanel;

import React from 'react';
import { Role, User } from '../types';

interface Props {
  onLogin: (user: User | null) => void;
  currentUser: User | null;
}

const LoginSimulator: React.FC<Props> = ({ onLogin, currentUser }) => {
  const roles: { label: string; role: Role; color: string }[] = [
    { label: 'Thành Viên', role: 'USER', color: 'bg-teal-100 text-teal-700' },
    { label: 'Quản Lý', role: 'MANAGER', color: 'bg-blue-100 text-blue-700' },
    { label: 'Admin', role: 'ADMIN', color: 'bg-purple-100 text-purple-700' },
  ];

  if (currentUser) {
    return (
      <div className="flex items-center gap-4 bg-white px-4 py-2 rounded-full border shadow-sm">
        <div className="w-8 h-8 rounded-full bg-teal-500 flex items-center justify-center text-white font-bold">
          {currentUser.name[0]}
        </div>
        <div>
          <p className="text-xs font-bold leading-none">{currentUser.name}</p>
          <p className="text-[10px] text-gray-400 uppercase tracking-tighter">{currentUser.role}</p>
        </div>
        <button 
          onClick={() => onLogin(null)}
          className="text-xs text-red-500 hover:font-bold ml-2 transition-all"
        >
          Đăng xuất
        </button>
      </div>
    );
  }

  return (
    <div className="flex flex-col items-center gap-2">
      <p className="text-xs text-gray-500 font-medium">ĐĂNG NHẬP NHANH:</p>
      <div className="flex gap-2">
        {roles.map(r => (
          <button 
            key={r.role}
            onClick={() => onLogin({ id: r.role, name: `Demo ${r.label}`, role: r.role })}
            className={`px-4 py-1.5 rounded-full text-xs font-bold transition-all hover:scale-105 active:scale-95 ${r.color} border border-transparent hover:border-current`}
          >
            {r.label}
          </button>
        ))}
      </div>
    </div>
  );
};

export default LoginSimulator;

import React from 'react';

interface Props {
  notifications: string[];
}

const NotificationList: React.FC<Props> = ({ notifications }) => {
  return (
    <div className="bg-white rounded-xl shadow-lg p-4 border border-teal-50 border-t-4 border-t-teal-600 h-full">
      <div className="flex items-center justify-between mb-3">
        <h4 className="text-xs font-black text-teal-900 uppercase tracking-widest">Thông báo (5)</h4>
        <span className="animate-ping w-2 h-2 bg-red-500 rounded-full"></span>
      </div>

      <div className="space-y-3">
        {notifications.length === 0 ? (
          <div className="text-center py-8">
            <span className="text-2xl opacity-20">🔕</span>
            <p className="text-[10px] text-gray-400 mt-2">Chưa có thông báo mới nào cho bạn hôm nay.</p>
          </div>
        ) : (
          notifications.map((n, i) => (
