      <div className="mt-6 pt-4 border-t border-gray-100">
        <button 
          onClick={() => alert("Chế độ nhắc giờ tập đã được bật cho các lớp bạn theo dõi!")}
          className="w-full bg-slate-900 text-white text-[10px] font-bold py-2 rounded-lg hover:bg-black transition-colors flex items-center justify-center gap-2"
        >
          ⏰ BẬT NHẮC GIỜ TẬP
        </button>
      </div>
    </div>
  );
};

export default NotificationList;

{
  "name": "GX Schedule - Ciputra Club",
  "description": "Hệ thống quản lý lịch tập Group Fitness chuyên nghiệp cho Ciputra Club.",
  "requestFramePermissions": [
    "notifications"
  ]
}

export type Role = 'USER' | 'MANAGER' | 'ADMIN';

export interface User {
  id: string;
  name: string;
  email: string;
  role: Role;
  avatar?: string;
}

export type ClassStatus = 'NORMAL' | 'CANCELLED' | 'SUBSTITUTE';

export interface ClassSession {
  id: string;
  dayIndex: number; // 0 = Mon, 6 = Sun
  time: string;
  className: string;
  instructor: string;
  category: 'YOGA' | 'TAICHI' | 'DANCE' | 'OTHER';
  status: ClassStatus;
  subInstructor?: string;
}

export interface HeaderConfig {
  logo: string;
  address: string;
  hotline: string;
  website: string;
}

export const DAYS_OF_WEEK = [
  { short: 'T2', long: 'THỨ HAI', eng: 'MONDAY' },
  { short: 'T3', long: 'THỨ BA', eng: 'TUESDAY' },
  { short: 'T4', long: 'THỨ TƯ', eng: 'WEDNESDAY' },
  { short: 'T5', long: 'THỨ NĂM', eng: 'THURSDAY' },
  { short: 'T6', long: 'THỨ SÁU', eng: 'FRIDAY' },
  { short: 'T7', long: 'THỨ BẢY', eng: 'SATURDAY' },
  { short: 'CN', long: 'CHỦ NHẬT', eng: 'SUNDAY' },
];

export const CATEGORY_COLORS = {
  YOGA: 'bg-sky-500',
  TAICHI: 'bg-emerald-600',
  DANCE: 'bg-orange-500',
  OTHER: 'bg-indigo-500'
};

import React, { useState, useEffect } from 'react';
import { Role, User, ClassSession, HeaderConfig, DAYS_OF_WEEK } from './types';
import Header from './components/Header';
import ScheduleGrid from './components/ScheduleGrid';
import ScheduleList from './components/ScheduleList';
import DateStrip from './components/DateStrip';
import AdminPanel from './components/AdminPanel';
import PWAInstaller from './components/PWAInstaller';

const DEFAULT_HEADER: HeaderConfig = {
  logo: 'https://ciputraclub.vn/wp-content/uploads/2018/06/logo-ciputra-club.png',
  address: 'Xuan Dinh, Bac Tu Liem, Hanoi',
  hotline: '0243 743 0666',
  website: 'www.ciputraclub.vn'
};

const INITIAL_SCHEDULE: ClassSession[] = [
  { id: '1', dayIndex: 0, time: '07:30 - 08:30', className: 'MIX YOGA', instructor: 'ANJALI', category: 'YOGA', status: 'NORMAL' },
  { id: '2', dayIndex: 1, time: '09:15 - 10:15', className: 'ZUMBA DANCE', instructor: 'LINH', category: 'DANCE', status: 'NORMAL' },
  { id: '3', dayIndex: 2, time: '08:45 - 09:45', className: 'TAICHI', instructor: 'TRƯỜNG', category: 'TAICHI', status: 'NORMAL' },
  { id: '4', dayIndex: 4, time: '18:00 - 19:00', className: 'HATHA YOGA', instructor: 'TRUNG', category: 'YOGA', status: 'SUBSTITUTE', subInstructor: 'ANJALI' },
  { id: '5', dayIndex: 6, time: '08:45 - 09:45', className: 'TAICHI', instructor: 'TRƯỜNG', category: 'TAICHI', status: 'CANCELLED' },
];

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [schedule, setSchedule] = useState<ClassSession[]>(INITIAL_SCHEDULE);
  const [headerConfig, setHeaderConfig] = useState<HeaderConfig>(DEFAULT_HEADER);
  const [selectedDayIndex, setSelectedDayIndex] = useState(new Date().getDay() === 0 ? 6 : new Date().getDay() - 1);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);
  const [managers, setManagers] = useState<User[]>([
    { id: 'm1', name: 'Manager Duy', email: 'manager@ciputra.com', role: 'MANAGER' }
  ]);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    window.addEventListener('resize', handleResize);

    const saved = localStorage.getItem('gx_schedule_v2');
    const savedHeader = localStorage.getItem('gx_header');
    if (saved) setSchedule(JSON.parse(saved));
    if (savedHeader) setHeaderConfig(JSON.parse(savedHeader));

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleUpdateSchedule = (newSchedule: ClassSession[]) => {
    setSchedule(newSchedule);
    localStorage.setItem('gx_schedule_v2', JSON.stringify(newSchedule));
  };

  const handleUpdateHeader = (config: HeaderConfig) => {
    setHeaderConfig(config);
    localStorage.setItem('gx_header', JSON.stringify(config));
  };

  const handleSetRole = (email: string, role: Role) => {
    // Simulation of admin action
    if (role === 'MANAGER') {
       const exists = managers.find(m => m.email === email);
       if (!exists) setManagers([...managers, { id: Date.now().toString(), name: email.split('@')[0], email, role: 'MANAGER' }]);
    } else {
       setManagers(managers.filter(m => m.email !== email));
    }
  };

  const loginAs = (role: Role) => {
    const mockUser: User = {
      id: role,
      name: role === 'ADMIN' ? 'Admin Boss' : role === 'MANAGER' ? 'Manager Duy' : 'Hội Viên',
      email: `${role.toLowerCase()}@example.com`,
      role: role,
      avatar: `https://api.dicebear.com/7.x/avataaars/svg?seed=${role}`
    };
    setCurrentUser(mockUser);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header config={headerConfig} user={currentUser} onLogin={loginAs} />

      <main className="flex-1 max-w-[1440px] mx-auto w-full px-0 sm:px-4 py-4 lg:py-8">
        <div className="px-4 mb-6 text-center lg:text-left">
          <h2 className="text-2xl lg:text-4xl font-black text-teal-900 uppercase tracking-tight">
            Lịch GX - Tháng {new Date().getMonth() + 1}/{new Date().getFullYear()}
          </h2>
          <p className="text-gray-500 text-sm mt-1">Cập nhật thời gian thực từ Ciputra Fitness Team</p>
        </div>

        {isMobile ? (
          <div className="flex flex-col gap-4">
            <DateStrip selected={selectedDayIndex} onSelect={setSelectedDayIndex} />
            <ScheduleList 
              dayIndex={selectedDayIndex} 
              schedule={schedule} 
              user={currentUser} 
              onUpdate={handleUpdateSchedule}
            />
          </div>
        ) : (
          <ScheduleGrid 
            schedule={schedule} 
            user={currentUser} 
            onUpdate={handleUpdateSchedule} 
          />
        )}

        {(currentUser?.role === 'ADMIN' || currentUser?.role === 'MANAGER') && (
          <div className="mt-8 px-4">
            <AdminPanel 
              user={currentUser}
              headerConfig={headerConfig}
              onUpdateHeader={handleUpdateHeader}
              managers={managers}
              onSetRole={handleSetRole}
            />
          </div>
        )}

        {isMobile && <PWAInstaller />}

        <footer className="mt-12 px-4 pb-8 text-center text-gray-400 text-xs">
          <p>© {new Date().getFullYear()} Ciputra Club Fitness. All Rights Reserved.</p>
          <p className="mt-2 italic">Lưu ý: Lịch học có thể thay đổi đột xuất tùy theo điều kiện thực tế.</p>
        </footer>
      </main>
    </div>
  );
};

export default App;

