export default DateStrip;

import React, { useState } from 'react';
import { ClassSession, User, CATEGORY_COLORS } from '../types';
import ClassModal from './ClassModal';

interface Props {
  dayIndex: number;
  schedule: ClassSession[];
  user: User | null;
  onUpdate: (newSchedule: ClassSession[]) => void;
}

const ScheduleList: React.FC<Props> = ({ dayIndex, schedule, user, onUpdate }) => {
  const [editingSession, setEditingSession] = useState<ClassSession | null>(null);
  const isManager = user?.role === 'ADMIN' || user?.role === 'MANAGER';

  const dayClasses = schedule
    .filter(s => s.dayIndex === dayIndex)
    .sort((a, b) => a.time.localeCompare(b.time));

  const handleSave = (session: ClassSession) => {
    if (session.id) {
      onUpdate(schedule.map(s => s.id === session.id ? session : s));
    } else {
      onUpdate([...schedule, { ...session, id: Date.now().toString() }]);
    }
    setEditingSession(null);
  };

  const handleDelete = (id: string) => {
    onUpdate(schedule.filter(s => s.id !== id));
    setEditingSession(null);
  };

  return (
    <div className="px-4 space-y-4 pb-20">
      {dayClasses.length === 0 ? (
        <div className="bg-white rounded-3xl p-12 text-center border-2 border-dashed border-gray-200">
          <span className="text-4xl mb-4 block">🧘‍♂️</span>
          <p className="text-gray-400 font-bold uppercase text-sm tracking-widest">Không có lớp học nào</p>
          <p className="text-xs text-gray-300 mt-2 italic">Dành thời gian nghỉ ngơi bạn nhé!</p>
        </div>
      ) : (
        dayClasses.map(session => (
          <div 
            key={session.id}
            onClick={() => isManager && setEditingSession(session)}
            className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden flex animate-fade relative"
          >
            {/* Category Color Indicator */}
            <div className={`w-3 ${CATEGORY_COLORS[session.category] || 'bg-gray-400'}`} />

            <div className="flex-1 p-5 flex flex-col justify-between">
              <div>
                <div className="flex justify-between items-start mb-1">
                  <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{session.time}</span>
                  {session.status === 'CANCELLED' && (
                    <span className="bg-red-100 text-red-600 text-[9px] font-black px-2 py-0.5 rounded-full uppercase">Đã Hủy</span>
                  )}
                  {session.status === 'SUBSTITUTE' && (
                    <span className="bg-orange-100 text-orange-600 text-[9px] font-black px-2 py-0.5 rounded-full uppercase">Dạy Thay</span>
                  )}
                </div>
                <h3 className={`text-xl font-black leading-tight mb-1 ${session.status === 'CANCELLED' ? 'line-through text-gray-300' : 'text-teal-900'}`}>
                  {session.className}
                </h3>
                <p className="text-gray-500 font-bold text-sm uppercase">
                  HLV: {session.status === 'SUBSTITUTE' ? <span>{session.subInstructor} <span className="text-xs text-gray-300 italic">(Thay cho {session.instructor})</span></span> : session.instructor}
                </p>
              </div>

              <div className="mt-4 flex gap-2">
                <button 
                  onClick={(e) => { e.stopPropagation(); alert("Đã đặt nhắc nhở!"); }}
                  className="flex-1 bg-teal-50 text-teal-700 py-2 rounded-2xl text-[10px] font-black uppercase tracking-wider hover:bg-teal-100 active:scale-95 transition-all flex items-center justify-center gap-2"
                >
                  🔔 Nhắc Tôi
                </button>
                {isManager && (
                  <button className="w-10 h-10 bg-gray-100 text-gray-400 rounded-2xl flex items-center justify-center">
                    ✏️
                  </button>
                )}
              </div>
            </div>
          </div>
        ))
      )}

      {isManager && (
        <button 
          onClick={() => setEditingSession({ id: '', dayIndex, time: '09:00 - 10:00', className: '', instructor: '', category: 'OTHER', status: 'NORMAL' })}
          className="w-full bg-slate-900 text-white py-4 rounded-3xl font-black text-sm uppercase tracking-widest shadow-xl active:scale-95 transition-all mt-4"
        >
          + THÊM LỚP MỚI
        </button>
      )}

      {editingSession && (
        <ClassModal 
          session={editingSession} 
          onClose={() => setEditingSession(null)} 
          onSave={handleSave} 
          onDelete={handleDelete} 
        />
      )}
    </div>
  );
};

export default ScheduleList;

import React, { useState } from 'react';
import { ClassSession, User, DAYS_OF_WEEK, CATEGORY_COLORS } from '../types';
import ClassModal from './ClassModal';

interface Props {
  schedule: ClassSession[];
  user: User | null;
  onUpdate: (newSchedule: ClassSession[]) => void;
}

const ScheduleGrid: React.FC<Props> = ({ schedule, user, onUpdate }) => {
  const [editingSession, setEditingSession] = useState<ClassSession | null>(null);
  const isManager = user?.role === 'ADMIN' || user?.role === 'MANAGER';

  const handleSave = (session: ClassSession) => {
    if (session.id) {
      onUpdate(schedule.map(s => s.id === session.id ? session : s));
    } else {
      onUpdate([...schedule, { ...session, id: Date.now().toString() }]);
    }
    setEditingSession(null);
  };

  const handleDelete = (id: string) => {
    onUpdate(schedule.filter(s => s.id !== id));
    setEditingSession(null);
  };

  return (
    <div className="bg-white rounded-[2rem] shadow-2xl overflow-hidden border border-gray-200 mx-4">
      {/* Table Header */}
      <div className="grid grid-cols-7 bg-teal-900 text-white border-b-4 border-teal-800">
        {DAYS_OF_WEEK.map((day, idx) => (
          <div key={idx} className="p-4 text-center border-r border-teal-800/50 last:border-0">
            <div className="text-[10px] font-black text-teal-300 tracking-widest uppercase">{day.eng}</div>
            <div className="text-lg font-black">{day.long}</div>
          </div>
        ))}
      </div>

      {/* Table Content */}
      <div className="grid grid-cols-7 divide-x divide-gray-100 bg-slate-50 min-h-[600px]">
        {DAYS_OF_WEEK.map((_, dayIdx) => {
          const sessions = schedule
            .filter(s => s.dayIndex === dayIdx)
            .sort((a, b) => a.time.localeCompare(b.time));

          return (
            <div key={dayIdx} className="p-3 space-y-3">
              {sessions.map(session => (
                <div 
                  key={session.id}
                  onClick={() => isManager && setEditingSession(session)}
                  className={`group relative flex flex-col bg-white rounded-2xl border border-gray-200 shadow-sm transition-all duration-300 ${isManager ? 'cursor-pointer hover:ring-4 hover:ring-teal-500/20 hover:scale-[1.03]' : ''}`}
                >
                  <div className="p-3 text-center">
                    <div className="text-[9px] font-black text-gray-400 mb-1 tracking-tighter">{session.time}</div>
                    <div className={`text-[11px] font-black text-white py-1.5 px-2 rounded-xl uppercase leading-none mb-1 shadow-sm ${CATEGORY_COLORS[session.category]}`}>
                      {session.className}
                    </div>
                    <div className="text-[10px] font-black text-teal-800 uppercase tracking-tight">
                      {session.status === 'SUBSTITUTE' ? session.subInstructor : session.instructor}
                    </div>
                  </div>

                  {session.status !== 'NORMAL' && (
                    <div className={`absolute -top-1 -right-1 px-1.5 py-0.5 rounded-lg text-[8px] font-black uppercase shadow-sm ${session.status === 'CANCELLED' ? 'bg-red-500 text-white' : 'bg-orange-400 text-white'}`}>
                      {session.status === 'CANCELLED' ? 'HỦY' : 'THAY'}
                    </div>
                  )}

                  {isManager && (
                    <div className="absolute inset-0 bg-teal-900/10 opacity-0 group-hover:opacity-100 rounded-2xl transition-opacity flex items-center justify-center">
                      <span className="bg-white text-teal-900 text-[10px] font-black px-3 py-1 rounded-full shadow-lg">CHỈNH SỬA</span>
                    </div>
                  )}
                </div>
              ))}
              {isManager && (
                <button 
                  onClick={() => setEditingSession({ id: '', dayIndex: dayIdx, time: '09:00 - 10:00', className: '', instructor: '', category: 'OTHER', status: 'NORMAL' })}
                  className="w-full border-2 border-dashed border-gray-200 rounded-2xl py-3 text-gray-300 hover:text-teal-500 hover:border-teal-200 transition-all font-black text-[10px] uppercase"
                >
                  + Thêm Lớp
                </button>
              )}
            </div>
          );
        })}
      </div>

      {editingSession && (
        <ClassModal 
          session={editingSession} 
          onClose={() => setEditingSession(null)} 
          onSave={handleSave} 
          onDelete={handleDelete} 
        />
      )}
    </div>
  );
};

export default ScheduleGrid;

import React, { useState } from 'react';
import { ClassSession, CATEGORY_COLORS, ClassStatus, DAYS_OF_WEEK } from '../types';

interface Props {
  session: ClassSession;
  onClose: () => void;
  onSave: (session: ClassSession) => void;
  onDelete: (id: string) => void;
}

const ClassModal: React.FC<Props> = ({ session, onClose, onSave, onDelete }) => {
  const [form, setForm] = useState<ClassSession>(session);

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-teal-900/40 backdrop-blur-md p-4">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg overflow-hidden animate-fade">
        <div className="bg-teal-900 p-8 text-white flex justify-between items-center">
          <div>
            <h3 className="text-2xl font-black uppercase tracking-tight">{session.id ? 'Cập Nhật Lịch' : 'Thêm Lớp Mới'}</h3>
            <p className="text-teal-400 text-xs font-bold uppercase mt-1">Quản lý lớp Group Fitness</p>
          </div>
          <button onClick={onClose} className="bg-teal-800 p-3 rounded-2xl hover:bg-red-500 transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
        </div>

        <div className="p-8 grid grid-cols-2 gap-6">
          <div className="col-span-2 sm:col-span-1">
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Thứ Trong Tuần</label>
            <select 
              className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl p-4 text-sm font-bold outline-none focus:border-teal-500 transition-all"
              value={form.dayIndex}
              onChange={e => setForm({...form, dayIndex: parseInt(e.target.value)})}
            >
              {DAYS_OF_WEEK.map((d, i) => <option key={i} value={i}>{d.long}</option>)}
            </select>
          </div>

          <div className="col-span-2 sm:col-span-1">
            <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Thời Gian (HH:MM - HH:MM)</label>
            <input 
              type="text" 
