import React, { useState, useEffect } from 'react';
import { Role, User, ClassSession, HeaderConfig, PermissionRecord } from './types';
import Header from './components/Header';
import ScheduleGrid from './components/ScheduleGrid';
import ScheduleList from './components/ScheduleList';
import DateStrip from './components/DateStrip';
import AdminPanel from './components/AdminPanel';
import PWAInstaller from './components/PWAInstaller';

const DEFAULT_HEADER: HeaderConfig = {
  logo: 'https://ciputraclub.vn/wp-content/uploads/2018/06/logo-ciputra-club.png',
  address: 'Xuan Dinh, Bac Tu Liem, Hanoi',
  hotline: '0243 743 0666',
  website: 'www.ciputraclub.vn'
};

const INITIAL_PERMISSIONS: PermissionRecord[] = [
  { email: 'admin@ciputraclub.vn', role: 'ADMIN', addedAt: new Date().toISOString() },
  { email: 'manager@ciputraclub.vn', role: 'MANAGER', addedAt: new Date().toISOString() }
];

const INITIAL_SCHEDULE: ClassSession[] = [
  { id: '1', dayIndex: 0, time: '07:30 - 08:30', className: 'MIX YOGA', instructor: 'ANJALI', category: 'YOGA', status: 'NORMAL' },
  { id: '2', dayIndex: 1, time: '09:15 - 10:15', className: 'ZUMBA DANCE', instructor: 'LINH', category: 'DANCE', status: 'NORMAL' },
];

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [schedule, setSchedule] = useState<ClassSession[]>(INITIAL_SCHEDULE);
  const [headerConfig, setHeaderConfig] = useState<HeaderConfig>(DEFAULT_HEADER);
  const [permissions, setPermissions] = useState<PermissionRecord[]>(INITIAL_PERMISSIONS);
  const [selectedDayIndex, setSelectedDayIndex] = useState(new Date().getDay() === 0 ? 6 : new Date().getDay() - 1);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    window.addEventListener('resize', handleResize);

    // Load data from storage
    const savedSchedule = localStorage.getItem('gx_schedule_v4');
    const savedPerms = localStorage.getItem('gx_permissions');
    const savedHeader = localStorage.getItem('gx_header');

    if (savedSchedule) setSchedule(JSON.parse(savedSchedule));
    if (savedPerms) setPermissions(JSON.parse(savedPerms));
    if (savedHeader) setHeaderConfig(JSON.parse(savedHeader));

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleUpdateSchedule = (newSchedule: ClassSession[]) => {
    setSchedule(newSchedule);
    localStorage.setItem('gx_schedule_v4', JSON.stringify(newSchedule));
  };

  const handleUpdatePermissions = (newPerms: PermissionRecord[]) => {
    setPermissions(newPerms);
    localStorage.setItem('gx_permissions', JSON.stringify(newPerms));
  };

  const handleUpdateHeader = (config: HeaderConfig) => {
    setHeaderConfig(config);
    localStorage.setItem('gx_header', JSON.stringify(config));
  };

  // Giả lập Login Google
  const handleGoogleLogin = (email: string, name: string, photo: string) => {
    // Tìm email trong danh sách quyền
    const userPerm = permissions.find(p => p.email.toLowerCase() === email.toLowerCase());
    const role: Role = userPerm ? userPerm.role : 'USER';

    const user: User = {
      id: btoa(email),
      name: name,
      email: email,
      role: role,
      avatar: photo
    };

    setCurrentUser(user);
    if (userPerm) {
      alert(`Chào mừng ${name}! Bạn đã đăng nhập với quyền ${role}.`);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header 
        config={headerConfig} 
        user={currentUser} 
        onGoogleLogin={handleGoogleLogin}
        onLogout={() => setCurrentUser(null)} 
      />

      <main className="flex-1 max-w-[1440px] mx-auto w-full px-0 sm:px-4 py-4 lg:py-8">
        <div className="px-4 mb-6 text-center">
          <h2 className="text-2xl lg:text-4xl font-black text-teal-900 uppercase tracking-tight">
            Lịch GX - Tháng {new Date().getMonth() + 1}/{new Date().getFullYear()}
          </h2>
          <p className="text-gray-500 text-sm mt-1">Hệ thống cập nhật thời gian thực Ciputra Fitness</p>
        </div>

        {isMobile ? (
          <div className="flex flex-col gap-4">
            <DateStrip selected={selectedDayIndex} onSelect={setSelectedDayIndex} />
            <ScheduleList dayIndex={selectedDayIndex} schedule={schedule} user={currentUser} onUpdate={handleUpdateSchedule} />
          </div>
        ) : (
          <ScheduleGrid schedule={schedule} user={currentUser} onUpdate={handleUpdateSchedule} />
        )}

        {currentUser?.role === 'ADMIN' && (
          <div className="mt-12 px-4 animate-fade">
            <AdminPanel 
              user={currentUser} 
              headerConfig={headerConfig} 
              onUpdateHeader={handleUpdateHeader} 
              permissions={permissions}
              onUpdatePermissions={handleUpdatePermissions}
            />
          </div>
        )}

        {isMobile && <PWAInstaller />}

        <footer className="mt-12 px-4 pb-8 text-center text-gray-400 text-xs">
          <p>© {new Date().getFullYear()} Ciputra Club Fitness. Quản lý bởi Fitness Team.</p>
        </footer>
      </main>
    </div>
  );
};

