            <p className="text-[9px] text-teal-400 font-bold uppercase mt-1 tracking-[0.2em]">Group Fitness</p>
          </div>
        </div>

        {/* User Actions */}
        <div className="flex items-center gap-4">
          {!user ? (
            <button 
              onClick={simulateGoogleAuth}
              disabled={isLoggingIn}
              className="flex items-center gap-3 bg-white text-gray-700 px-4 py-2.5 rounded-full text-xs font-bold shadow-md hover:bg-gray-50 transition-all active:scale-95 border border-gray-200"
