              <span>{isLoggingIn ? 'Đang kết nối...' : 'Đăng nhập Google'}</span>
            </button>
          ) : (
            <div className="flex items-center gap-3 bg-teal-800/40 pr-1 pl-4 py-1 rounded-full border border-teal-700/50">
              <div className="text-right hidden xs:block">
