                            className={`px-6 py-2 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${
                              role === 'MANAGER' ? 'bg-red-50 text-red-600' : 'bg-teal-600 text-white shadow-lg shadow-teal-600/20'
