            </div>
          )}

          {activeTab === 'SYSTEM' && (
            <div className="animate-fade">
               <div className="bg-slate-50 p-10 rounded-[3rem] border-2 border-dashed border-slate-200 text-center">
                 <p className="text-gray-400 font-bold">Tính năng cấu hình Logo và Hotline đang được hoàn thiện...</p>
               </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

