              <div className="flex justify-between items-center border-b pb-4">
                <h3 className="text-xl font-black text-teal-900 uppercase">Danh sách Nhân sự & Hội viên</h3>
                <span className="bg-teal-100 text-teal-700 px-4 py-1.5 rounded-full text-[10px] font-black">{registeredUsers.length} TÀI KHOẢN</span>
              </div>
              <div className="grid gap-4">
                {registeredUsers.map(regUser => {
                  const currentPerm = permissions.find(p => p.email === regUser.email);
                  const role = currentPerm?.role || 'USER';
                  const isRoot = regUser.email === rootEmail;
                  return (
                    <div key={regUser.id} className="flex items-center justify-between bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                      <div className="flex items-center gap-4">
                        <img src={regUser.avatar} className="w-12 h-12 rounded-full border-2 border-teal-500 p-0.5" alt="avt" />
                        <div><p className="text-xs font-black text-gray-800 uppercase">{regUser.name}</p><p className="text-[10px] text-gray-400 font-bold">{regUser.email}</p></div>
                      </div>
                      <div className="flex items-center gap-3">
                        <div className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${role === 'ADMIN' ? 'bg-purple-100 text-purple-600' : role === 'MANAGER' ? 'bg-amber-100 text-amber-600' : 'bg-slate-100 text-slate-500'}`}>{role}</div>
                        {!isRoot && user?.role === 'ADMIN' && (
                          <button onClick={() => toggleUserRole(regUser.email, role)} className={`px-6 py-2 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${role === 'MANAGER' ? 'bg-red-50 text-red-600' : 'bg-teal-600 text-white'}`}>
                            {role === 'MANAGER' ? 'Hạ cấp User' : 'Set Manager'}
                          </button>
                        )}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
          {activeTab === 'SYSTEM' && <div className="p-10 text-center text-gray-400 font-bold italic">Cấu hình nâng cao đang được cập nhật...</div>}
        </div>
      </div>
    </div>
  );
};

