import React, { useState } from 'react';
import { User, HeaderConfig, Role, PermissionRecord, ClassSession, DAYS_OF_WEEK } from '../types';

interface Props {
  user: User | null;
  headerConfig: HeaderConfig;
  onUpdateHeader: (c: HeaderConfig) => void;
  permissions: PermissionRecord[];
  onUpdatePermissions: (p: PermissionRecord[]) => void;
  rootEmail: string;
  onClose: () => void;
  registeredUsers: User[];
  schedule: ClassSession[];
  onUpdateSchedule: (s: ClassSession[]) => void;
  onNotify: (msg: string, type: 'INFO' | 'ALERT') => void;
}

const AdminPanel: React.FC<Props> = ({ 
  user, headerConfig, onUpdateHeader, permissions, 
  onUpdatePermissions, rootEmail, onClose, registeredUsers,
  schedule, onUpdateSchedule, onNotify
}) => {
  const [activeTab, setActiveTab] = useState<'SCHEDULE' | 'USERS' | 'SYSTEM'>('SCHEDULE');
  const [broadcastMsg, setBroadcastMsg] = useState('');
  const [tempHeader, setTempHeader] = useState<HeaderConfig>({ ...headerConfig });

  const [newClass, setNewClass] = useState<Partial<ClassSession>>({
    dayIndex: 0,
    time: '08:00 - 09:00',
    className: '',
    instructor: '',
    category: 'YOGA',
    status: 'NORMAL'
  });

  const handleAddClass = () => {
    if (!newClass.className || !newClass.instructor) return alert("Nhập đủ tên lớp và HLV!");
    const session: ClassSession = {
      ...newClass as ClassSession,
      id: Date.now().toString()
    };
    onUpdateSchedule([...schedule, session]);
    setNewClass({...newClass, className: '', instructor: ''});

    if (confirm("Bạn có muốn gửi thông báo lớp mới này cho hội viên không?")) {
      onNotify(`Lớp mới: ${session.className} lúc ${session.time} (${DAYS_OF_WEEK[session.dayIndex].vn}) đã được thêm vào lịch!`, 'INFO');
    }
    alert("Đã thêm lớp thành công!");
  };

  const handleSendBroadcast = () => {
    if (!broadcastMsg.trim()) return;
    onNotify(broadcastMsg, 'INFO');
    setBroadcastMsg('');
    alert("Đã gửi thông báo tới tất cả hội viên!");
  };

  const handleSaveHeader = () => {
    onUpdateHeader(tempHeader);
    alert("Đã cập nhật cấu hình Header thành công!");
  };

  const toggleUserRole = (email: string, currentRole: Role) => {
    if (email.toLowerCase() === rootEmail.toLowerCase()) return alert("Root Admin là bất biến!");
    const newRole: Role = currentRole === 'MANAGER' ? 'USER' : 'MANAGER';
    const existingPerm = permissions.find(p => p.email === email);
    let updatedPerms;
    if (existingPerm) {
      updatedPerms = permissions.map(p => p.email === email ? { ...p, role: newRole } : p);
    } else {
      updatedPerms = [...permissions, { email, role: newRole, addedAt: new Date().toISOString() }];
    }
    onUpdatePermissions(updatedPerms);
  };

  return (
