  onUpdateSchedule: (s: ClassSession[]) => void;
  onNotify: (msg: string, type: 'INFO' | 'ALERT') => void;
}

const AdminPanel: React.FC<Props> = ({ 
  user, headerConfig, onUpdateHeader, permissions, 
  onUpdatePermissions, rootEmail, onClose, registeredUsers,
  schedule, onUpdateSchedule, onNotify
}) => {
  const [activeTab, setActiveTab] = useState<'SCHEDULE' | 'USERS' | 'SYSTEM'>('SCHEDULE');
  const [broadcastMsg, setBroadcastMsg] = useState('');
  const [tempHeader, setTempHeader] = useState<HeaderConfig>({ ...headerConfig });

  const [newClass, setNewClass] = useState<Partial<ClassSession>>({
    dayIndex: 0,
    time: '08:00 - 09:00',
    className: '',
    instructor: '',
    category: 'YOGA',
    status: 'NORMAL'
  });

  const handleAddClass = () => {
    if (!newClass.className || !newClass.instructor) return alert("Nhập đủ tên lớp và HLV!");
    const session: ClassSession = {
      ...newClass as ClassSession,
      id: Date.now().toString()
    };
    onUpdateSchedule([...schedule, session]);
    setNewClass({...newClass, className: '', instructor: ''});

    if (confirm("Bạn có muốn gửi thông báo lớp mới này cho hội viên không?")) {
      onNotify(`Lớp mới: ${session.className} lúc ${session.time} (${DAYS_OF_WEEK[session.dayIndex].vn}) đã được thêm vào lịch!`, 'INFO');
    }
    alert("Đã thêm lớp thành công!");
  };

  const handleSendBroadcast = () => {
    if (!broadcastMsg.trim()) return;
    onNotify(broadcastMsg, 'INFO');
    setBroadcastMsg('');
    alert("Đã gửi thông báo tới tất cả hội viên!");
  };

  const handleSaveHeader = () => {
    onUpdateHeader(tempHeader);
    alert("Đã cập nhật cấu hình Header thành công!");
  };

  const toggleUserRole = (email: string, currentRole: Role) => {
    if (email.toLowerCase() === rootEmail.toLowerCase()) return alert("Root Admin là bất biến!");
    const newRole: Role = currentRole === 'MANAGER' ? 'USER' : 'MANAGER';
    const existingPerm = permissions.find(p => p.email === email);
    let updatedPerms;
    if (existingPerm) {
      updatedPerms = permissions.map(p => p.email === email ? { ...p, role: newRole } : p);
    } else {
      updatedPerms = [...permissions, { email, role: newRole, addedAt: new Date().toISOString() }];
    }
    onUpdatePermissions(updatedPerms);
  };

  return (
    <div className="fixed inset-0 bg-teal-950/80 backdrop-blur-xl flex items-center justify-center p-4 lg:p-8">
      <div className="bg-white w-full max-w-6xl h-full max-h-[90vh] rounded-[3rem] shadow-2xl flex flex-col overflow-hidden">

        <div className="bg-teal-900 px-8 py-6 flex items-center justify-between text-white">
          <div className="flex items-center gap-4">
            <div className="bg-white/10 p-3 rounded-2xl">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/></svg>
            </div>
            <div>
              <h2 className="text-xl font-black uppercase tracking-tight">Quản Trị Hệ Thống</h2>
              <p className="text-[10px] text-teal-400 font-bold uppercase tracking-widest mt-0.5">Tài khoản: {user?.email}</p>
            </div>
          </div>
          <button onClick={onClose} className="p-3 bg-white/10 hover:bg-white/20 rounded-full transition-all">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M6 18L18 6M6 6l12 12" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
        </div>

        <div className="flex bg-slate-100 p-2 gap-2 border-b">
          {[
            { id: 'SCHEDULE', label: 'Lịch Tập & Thông báo', icon: '📅' },
            { id: 'USERS', label: 'Hội viên & Nhân sự', icon: '👥' },
            { id: 'SYSTEM', label: 'Cấu hình Website', icon: '⚙️' }
          ].map(tab => (
            <button key={tab.id} onClick={() => setActiveTab(tab.id as any)} className={`flex-1 py-4 px-6 rounded-2xl text-[11px] font-black uppercase tracking-wider transition-all flex items-center justify-center gap-3 ${activeTab === tab.id ? 'bg-white text-teal-900 shadow-md' : 'text-gray-400 hover:text-teal-700'}`}>
              <span>{tab.icon}</span> {tab.label}
            </button>
          ))}
        </div>

        <div className="flex-1 overflow-y-auto p-8 lg:p-12 custom-scroll">

          {activeTab === 'SCHEDULE' && (
            <div className="space-y-12 animate-fade">
              <section className="bg-amber-50 rounded-[2.5rem] p-8 border border-amber-100 shadow-sm">
                <h3 className="text-sm font-black text-amber-900 uppercase tracking-widest mb-6 flex items-center gap-3">
                   📢 Gửi thông báo khẩn cấp <span className="h-px flex-1 bg-amber-200"></span>
                </h3>
                <div className="flex gap-4">
                  <input className="flex-1 bg-white border-2 border-amber-100 rounded-2xl p-4 text-xs font-bold outline-none focus:border-amber-500 shadow-sm" value={broadcastMsg} onChange={e => setBroadcastMsg(e.target.value)} placeholder="Nhập nội dung thông báo cho toàn bộ hội viên..." />
                  <button onClick={handleSendBroadcast} className="bg-amber-600 text-white px-8 py-4 rounded-2xl font-black text-xs uppercase hover:bg-amber-700 transition-all shadow-lg">Gửi Tin</button>
                </div>
              </section>

              <section className="bg-teal-50 rounded-[2.5rem] p-8 border border-teal-100 shadow-sm">
                <h3 className="text-sm font-black text-teal-900 uppercase tracking-widest mb-8 flex items-center gap-3">
                   ➕ Thêm lớp học mới vào lịch <span className="h-px flex-1 bg-teal-100"></span>
                </h3>
                <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {/* Tên Môn */}
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Tên Môn Học</label>
                    <input className="w-full bg-white border-2 border-teal-100 rounded-2xl p-4 text-xs font-bold outline-none focus:border-teal-500" value={newClass.className} onChange={e => setNewClass({...newClass, className: e.target.value.toUpperCase()})} placeholder="ZUMBA, YOGA..." />
                  </div>

                  {/* Giáo Viên */}
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Giáo Viên (HLV)</label>
                    <input className="w-full bg-white border-2 border-teal-100 rounded-2xl p-4 text-xs font-bold outline-none focus:border-teal-500" value={newClass.instructor} onChange={e => setNewClass({...newClass, instructor: e.target.value.toUpperCase()})} placeholder="TÊN HLV" />
                  </div>

                  {/* Thời Gian */}
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Khung Giờ</label>
                    <input className="w-full bg-white border-2 border-teal-100 rounded-2xl p-4 text-xs font-bold outline-none focus:border-teal-500" value={newClass.time} onChange={e => setNewClass({...newClass, time: e.target.value})} placeholder="08:00 - 09:00" />
                  </div>

                  {/* Chọn Thứ */}
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Thứ Trong Tuần</label>
                    <select 
                      className="w-full bg-white border-2 border-teal-100 rounded-2xl p-4 text-xs font-bold outline-none focus:border-teal-500 appearance-none cursor-pointer"
                      value={newClass.dayIndex}
                      onChange={e => setNewClass({...newClass, dayIndex: parseInt(e.target.value)})}
                    >
                      {DAYS_OF_WEEK.map((day, idx) => (
                        <option key={idx} value={idx}>{day.vn} ({day.eng})</option>
                      ))}
                    </select>
                  </div>

                  {/* Nhóm môn (Màu sắc) */}
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase ml-2">Nhóm Môn (Màu nền)</label>
                    <select 
                      className="w-full bg-white border-2 border-teal-100 rounded-2xl p-4 text-xs font-bold outline-none focus:border-teal-500 appearance-none cursor-pointer"
                      value={newClass.category}
                      onChange={e => setNewClass({...newClass, category: e.target.value as any})}
                    >
                      <option value="YOGA">YOGA (Xanh Dương)</option>
                      <option value="TAICHI">TAI CHI (Xanh Lá)</option>
                      <option value="DANCE">DANCE / ZUMBA (Cam)</option>
                      <option value="OTHER">KHÁC (Tím)</option>
                    </select>
