};

export default AdminPanel;

export type Role = 'USER' | 'MANAGER' | 'ADMIN';

export interface User {
  id: string;
  name: string;
  email: string;
  role: Role;
  avatar?: string;
}

export interface PermissionRecord {
  email: string;
  role: Role;
  addedAt: string;
}

export type ClassStatus = 'NORMAL' | 'CANCELLED' | 'SUBSTITUTE';

export interface AppNotification {
  id: string;
  message: string;
  timestamp: string;
  type: 'INFO' | 'ALERT';
  sender: string;
}

export interface ClassSession {
  id: string;
  dayIndex: number;
  time: string;
  className: string;
  instructor: string;
  category: 'YOGA' | 'TAICHI' | 'DANCE' | 'OTHER';
  status: ClassStatus;
  subInstructor?: string;
}

export interface HeaderConfig {
  logo: string;
  address: string;
  hotline: string;
  website: string;
  scheduleTitle: string;
}

export const DAYS_OF_WEEK = [
  { vn: 'Thứ 2', eng: 'Monday' },
  { vn: 'Thứ 3', eng: 'Tuesday' },
  { vn: 'Thứ 4', eng: 'Wednesday' },
  { vn: 'Thứ 5', eng: 'Thursday' },
  { vn: 'Thứ 6', eng: 'Friday' },
  { vn: 'Thứ 7', eng: 'Saturday' },
  { vn: 'Chủ Nhật', eng: 'Sunday' },
];

export const CATEGORY_COLORS = {
  YOGA: 'bg-sky-500',
  TAICHI: 'bg-emerald-600',
  DANCE: 'bg-orange-500',
  OTHER: 'bg-indigo-500'
};

import React, { useState, useEffect } from 'react';
import { Role, User, ClassSession, HeaderConfig, PermissionRecord, AppNotification } from './types';
import Header from './components/Header';
import ScheduleGrid from './components/ScheduleGrid';
import ScheduleList from './components/ScheduleList';
import DateStrip from './components/DateStrip';
import AdminPanel from './components/AdminPanel';
import PWAInstaller from './components/PWAInstaller';
import NotificationList from './components/NotificationList';

const ROOT_ADMIN_EMAIL = 'admin@ciputraclub.vn'; 

const DEFAULT_HEADER: HeaderConfig = {
  logo: 'https://ciputraclub.vn/wp-content/uploads/2018/06/logo-ciputra-club.png',
  address: 'Xuan Dinh, Bac Tu Liem, Hanoi',
  hotline: '0243 743 0666',
  website: 'www.ciputraclub.vn',
  scheduleTitle: `Lịch GX - ${new Date().toLocaleDateString('vi-VN', { month: 'long', year: 'numeric' })}`
};

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [schedule, setSchedule] = useState<ClassSession[]>([]);
  const [headerConfig, setHeaderConfig] = useState<HeaderConfig>(DEFAULT_HEADER);
  const [permissions, setPermissions] = useState<PermissionRecord[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [showAdmin, setShowAdmin] = useState(false);
  const [userRegistry, setUserRegistry] = useState<User[]>([]);
  const [selectedDayIndex, setSelectedDayIndex] = useState(new Date().getDay() === 0 ? 6 : new Date().getDay() - 1);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    window.addEventListener('resize', handleResize);

    const savedSchedule = localStorage.getItem('gx_schedule_v7');
    const savedPerms = localStorage.getItem('gx_permissions_v7');
    const savedHeader = localStorage.getItem('gx_header_v7');
    const savedRegistry = localStorage.getItem('gx_user_registry_v7');
    const savedNotifs = localStorage.getItem('gx_notifications_v7');

    if (savedSchedule) setSchedule(JSON.parse(savedSchedule));

    if (savedHeader) {
      const parsedHeader = JSON.parse(savedHeader);
      // Ensure existing saved headers get the scheduleTitle property if they don't have it
      if (!parsedHeader.scheduleTitle) {
        parsedHeader.scheduleTitle = DEFAULT_HEADER.scheduleTitle;
      }
      setHeaderConfig(parsedHeader);
    }

    if (savedRegistry) setUserRegistry(JSON.parse(savedRegistry));
    if (savedNotifs) setNotifications(JSON.parse(savedNotifs));

    if (savedPerms) {
      setPermissions(JSON.parse(savedPerms));
    } else {
      const root: PermissionRecord = { 
        email: ROOT_ADMIN_EMAIL.toLowerCase(), 
        role: 'ADMIN', 
        addedAt: new Date().toISOString() 
      };
      setPermissions([root]);
      localStorage.setItem('gx_permissions_v7', JSON.stringify([root]));
    }

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleUpdateSchedule = (newSchedule: ClassSession[]) => {
    setSchedule(newSchedule);
    localStorage.setItem('gx_schedule_v7', JSON.stringify(newSchedule));
  };

  const handleUpdateNotifications = (newNotifs: AppNotification[]) => {
    setNotifications(newNotifs);
    localStorage.setItem('gx_notifications_v7', JSON.stringify(newNotifs));
  };

  const addNotification = (message: string, type: 'INFO' | 'ALERT' = 'INFO') => {
    const newNotif: AppNotification = {
      id: Date.now().toString(),
      message,
      timestamp: new Date().toISOString(),
      type,
      sender: currentUser?.name || 'Hệ thống'
    };
    handleUpdateNotifications([newNotif, ...notifications].slice(0, 20)); // Keep last 20
  };

  const handleGoogleLogin = (email: string, name: string, photo: string) => {
    const lowerEmail = email.toLowerCase();
    let role: Role = 'USER';
    if (lowerEmail === ROOT_ADMIN_EMAIL.toLowerCase()) {
      role = 'ADMIN';
    } else {
      const userPerm = permissions.find(p => p.email.toLowerCase() === lowerEmail);
      if (userPerm) role = userPerm.role;
    }

    const newUser: User = { id: btoa(lowerEmail), name, email: lowerEmail, role, avatar: photo };
    setCurrentUser(newUser);

    setUserRegistry(prev => {
      const exists = prev.find(u => u.email === lowerEmail);
      if (exists) return prev.map(u => u.email === lowerEmail ? newUser : u);
      const updated = [...prev, newUser];
      localStorage.setItem('gx_user_registry_v7', JSON.stringify(updated));
      return updated;
    });
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header 
        config={headerConfig} 
        user={currentUser} 
        onGoogleLogin={handleGoogleLogin}
        onLogout={() => { setCurrentUser(null); setShowAdmin(false); }} 
        onToggleAdmin={() => setShowAdmin(!showAdmin)}
      />

      <main className="flex-1 max-w-[1440px] mx-auto w-full px-0 sm:px-4 py-4 lg:py-8 pb-12">
        <div className="grid lg:grid-cols-12 gap-8 px-4 lg:px-0">

          <div className="lg:col-span-8 xl:col-span-9">
            <div className="mb-8 text-center lg:text-left">
              <h2 className="text-2xl lg:text-4xl font-black text-teal-900 uppercase tracking-tight">
                {headerConfig.scheduleTitle}
              </h2>
              <p className="text-gray-500 text-sm mt-1">Cập nhật lịch tập thời gian thực Ciputra Club</p>
            </div>

            {isMobile ? (
              <div className="flex flex-col gap-4">
                <DateStrip selected={selectedDayIndex} onSelect={setSelectedDayIndex} />
                <ScheduleList dayIndex={selectedDayIndex} schedule={schedule} user={currentUser} onUpdate={handleUpdateSchedule} />
              </div>
            ) : (
              <ScheduleGrid schedule={schedule} user={currentUser} onUpdate={handleUpdateSchedule} onNotify={addNotification} />
            )}
          </div>

          <aside className="lg:col-span-4 xl:col-span-3 space-y-6">
            <NotificationList notifications={notifications} />
            {isMobile && !showAdmin && <PWAInstaller />}
          </aside>
        </div>

        {showAdmin && (currentUser?.role === 'ADMIN' || currentUser?.role === 'MANAGER') && (
          <div className="fixed inset-0 z-[100] animate-fade">
             <AdminPanel 
              user={currentUser} 
              headerConfig={headerConfig} 
              onUpdateHeader={(c) => { setHeaderConfig(c); localStorage.setItem('gx_header_v7', JSON.stringify(c)); }} 
              permissions={permissions}
              onUpdatePermissions={(p) => { setPermissions(p); localStorage.setItem('gx_permissions_v7', JSON.stringify(p)); }}
              rootEmail={ROOT_ADMIN_EMAIL}
              onClose={() => setShowAdmin(false)}
              registeredUsers={userRegistry}
              schedule={schedule}
              onUpdateSchedule={handleUpdateSchedule}
              onNotify={addNotification}
            />
          </div>
        )}

        <footer className="mt-20 px-4 pb-12 text-center text-gray-400 text-[10px] sm:text-xs">
          <p>© 2026 Ciputra Club Fitness. Quản lý bởi Fitness Department.</p>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { User, HeaderConfig, Role, PermissionRecord, ClassSession, DAYS_OF_WEEK } from '../types';

interface Props {
  user: User | null;
  headerConfig: HeaderConfig;
  onUpdateHeader: (c: HeaderConfig) => void;
  permissions: PermissionRecord[];
  onUpdatePermissions: (p: PermissionRecord[]) => void;
  rootEmail: string;
  onClose: () => void;
  registeredUsers: User[];
  schedule: ClassSession[];
  onUpdateSchedule: (s: ClassSession[]) => void;
  onNotify: (msg: string, type: 'INFO' | 'ALERT') => void;
}

const AdminPanel: React.FC<Props> = ({ 
  user, headerConfig, onUpdateHeader, permissions, 
  onUpdatePermissions, rootEmail, onClose, registeredUsers,
  schedule, onUpdateSchedule, onNotify
}) => {
  const [activeTab, setActiveTab] = useState<'SCHEDULE' | 'USERS' | 'SYSTEM'>('SCHEDULE');
  const [broadcastMsg, setBroadcastMsg] = useState('');
  const [tempHeader, setTempHeader] = useState<HeaderConfig>({ ...headerConfig });

  const [newClass, setNewClass] = useState<Partial<ClassSession>>({
    dayIndex: 0,
    time: '08:00 - 09:00',
    className: '',
    instructor: '',
    category: 'YOGA',
    status: 'NORMAL'
  });

  const handleAddClass = () => {
    if (!newClass.className || !newClass.instructor) return alert("Nhập đủ tên lớp và HLV!");
    const session: ClassSession = {
      ...newClass as ClassSession,
      id: Date.now().toString()
    };
    onUpdateSchedule([...schedule, session]);
    setNewClass({...newClass, className: '', instructor: ''});

    if (confirm("Bạn có muốn gửi thông báo lớp mới này cho hội viên không?")) {
      onNotify(`Lớp mới: ${session.className} lúc ${session.time} (${DAYS_OF_WEEK[session.dayIndex].vn}) đã được thêm vào lịch!`, 'INFO');
    }
    alert("Đã thêm lớp thành công!");
  };

  const handleSendBroadcast = () => {
    if (!broadcastMsg.trim()) return;
    onNotify(broadcastMsg, 'INFO');
    setBroadcastMsg('');
    alert("Đã gửi thông báo tới tất cả hội viên!");
  };

  const handleSaveHeader = () => {
    onUpdateHeader(tempHeader);
    alert("Đã cập nhật cấu hình hệ thống thành công!");
  };

  const toggleUserRole = (email: string, currentRole: Role) => {
    if (email.toLowerCase() === rootEmail.toLowerCase()) return alert("Root Admin là bất biến!");
    const newRole: Role = currentRole === 'MANAGER' ? 'USER' : 'MANAGER';
    const existingPerm = permissions.find(p => p.email === email);
    let updatedPerms;
    if (existingPerm) {
      updatedPerms = permissions.map(p => p.email === email ? { ...p, role: newRole } : p);
    } else {
      updatedPerms = [...permissions, { email, role: newRole, addedAt: new Date().toISOString() }];
    }
    onUpdatePermissions(updatedPerms);
  };

  return (
    <div className="fixed inset-0 bg-teal-950/80 backdrop-blur-xl flex items-center justify-center p-4 lg:p-8">
