            </div>

            <div className="space-y-6">
              {/* NÚT GOOGLE THẬT SẼ ĐƯỢC RENDER VÀO ĐÂY */}
              <div id="googleBtn" className="min-h-[40px] flex justify-center"></div>

              <button 
                onClick={() => setShowLoginModal(false)}
                className="w-full bg-slate-100 text-slate-500 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-slate-200"
              >
                Đóng cửa sổ
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

