            <div className="space-y-4">
              {/* Nơi render nút Google thật */}
              <div id="googleBtn" className="min-h-[40px] flex justify-center"></div>

              <div className="relative py-2">
                <div className="absolute inset-0 flex items-center"><span className="w-full border-t border-gray-100"></span></div>
                <div className="relative flex justify-center text-[8px] uppercase font-black text-gray-300"><span className="bg-white px-2 italic">Hoặc truy cập nhanh</span></div>
              </div>

              {/* LỐI TẮT CHO CHỦ APP KHI CHƯA CÓ GOOGLE CLIENT ID */}
              <button 
                onClick={() => {
                   onGoogleLogin('admin@ciputraclub.vn', 'Quản Trị Viên', 'https://api.dicebear.com/7.x/avataaars/svg?seed=Admin');
                   setShowLoginModal(false);
                }}
                className="w-full bg-teal-50 text-teal-700 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-teal-100 border border-teal-100 transition-all"
              >
                🔐 Dùng thử quyền Admin
              </button>

              <button 
                onClick={() => setShowLoginModal(false)}
                className="w-full text-slate-400 py-2 font-black text-[9px] uppercase tracking-widest hover:text-slate-600"
              >
                Hủy bỏ
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};

export default Header;

import React, { useState, useEffect } from 'react';
import { Role, User, ClassSession, HeaderConfig, PermissionRecord, AppNotification } from './types';
import Header from './components/Header';
import ScheduleGrid from './components/ScheduleGrid';
import ScheduleList from './components/ScheduleList';
import DateStrip from './components/DateStrip';
import AdminPanel from './components/AdminPanel';
import PWAInstaller from './components/PWAInstaller';
import NotificationList from './components/NotificationList';

const ROOT_ADMIN_EMAIL = 'admin@ciputraclub.vn'; 

const DEFAULT_HEADER: HeaderConfig = {
  logo: 'https://ciputraclub.vn/wp-content/uploads/2018/06/logo-ciputra-club.png',
  address: 'Xuan Dinh, Bac Tu Liem, Hanoi',
  hotline: '0243 743 0666',
  website: 'www.ciputraclub.vn',
  scheduleTitle: `Lịch GX - THÁNG ${new Date().getMonth() + 1} NĂM ${new Date().getFullYear()}`
};

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [schedule, setSchedule] = useState<ClassSession[]>([]);
  const [headerConfig, setHeaderConfig] = useState<HeaderConfig>(DEFAULT_HEADER);
  const [permissions, setPermissions] = useState<PermissionRecord[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [showAdmin, setShowAdmin] = useState(false);
  const [userRegistry, setUserRegistry] = useState<User[]>([]);
  const [selectedDayIndex, setSelectedDayIndex] = useState(new Date().getDay() === 0 ? 6 : new Date().getDay() - 1);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    window.addEventListener('resize', handleResize);

    // Tải dữ liệu từ LocalStorage
    const savedSchedule = localStorage.getItem('gx_schedule_v7');
    const savedPerms = localStorage.getItem('gx_permissions_v7');
    const savedHeader = localStorage.getItem('gx_header_v7');
    const savedRegistry = localStorage.getItem('gx_user_registry_v7');
    const savedNotifs = localStorage.getItem('gx_notifications_v7');

    if (savedSchedule) setSchedule(JSON.parse(savedSchedule));
    if (savedHeader) {
      const parsed = JSON.parse(savedHeader);
      // Giữ lại tiêu đề cũ nếu có, nếu không dùng mặc định
      setHeaderConfig({
        ...DEFAULT_HEADER,
        ...parsed,
        scheduleTitle: parsed.scheduleTitle || DEFAULT_HEADER.scheduleTitle
      });
    }
    if (savedRegistry) setUserRegistry(JSON.parse(savedRegistry));
    if (savedNotifs) setNotifications(JSON.parse(savedNotifs));

    if (savedPerms) {
      setPermissions(JSON.parse(savedPerms));
    } else {
      const root: PermissionRecord = { email: ROOT_ADMIN_EMAIL, role: 'ADMIN', addedAt: new Date().toISOString() };
      setPermissions([root]);
      localStorage.setItem('gx_permissions_v7', JSON.stringify([root]));
    }

    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const handleUpdateSchedule = (newSchedule: ClassSession[]) => {
    setSchedule(newSchedule);
    localStorage.setItem('gx_schedule_v7', JSON.stringify(newSchedule));
  };

  const handleUpdateHeader = (newHeader: HeaderConfig) => {
    setHeaderConfig(newHeader);
    localStorage.setItem('gx_header_v7', JSON.stringify(newHeader));
  };

  const addNotification = (message: string, type: 'INFO' | 'ALERT' = 'INFO') => {
    const newNotif: AppNotification = {
      id: Date.now().toString(),
      message,
      timestamp: new Date().toISOString(),
      type,
      sender: currentUser?.name || 'Hệ thống'
    };
    const updated = [newNotif, ...notifications].slice(0, 20);
    setNotifications(updated);
    localStorage.setItem('gx_notifications_v7', JSON.stringify(updated));
  };

  const handleGoogleLogin = (email: string, name: string, photo: string) => {
    const lowerEmail = email.toLowerCase();
    let role: Role = 'USER';

    if (lowerEmail === ROOT_ADMIN_EMAIL) {
      role = 'ADMIN';
    } else {
      const userPerm = permissions.find(p => p.email.toLowerCase() === lowerEmail);
      if (userPerm) role = userPerm.role;
    }

    const newUser: User = { id: btoa(lowerEmail), name, email: lowerEmail, role, avatar: photo };
    setCurrentUser(newUser);

    setUserRegistry(prev => {
      const exists = prev.find(u => u.email === lowerEmail);
      if (exists) return prev.map(u => u.email === lowerEmail ? newUser : u);
      const updated = [...prev, newUser];
      localStorage.setItem('gx_user_registry_v7', JSON.stringify(updated));
      return updated;
    });
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header 
        config={headerConfig} 
        user={currentUser} 
        onGoogleLogin={handleGoogleLogin}
        onLogout={() => { setCurrentUser(null); setShowAdmin(false); }} 
        onToggleAdmin={() => setShowAdmin(!showAdmin)}
      />

      <main className="flex-1 max-w-[1440px] mx-auto w-full px-0 sm:px-4 py-4 lg:py-8 pb-12">
        <div className="grid lg:grid-cols-12 gap-8 px-4 lg:px-0">

          <div className="lg:col-span-8 xl:col-span-9">
            <div className="mb-8 text-center lg:text-left">
              <h2 className="text-2xl lg:text-4xl font-black text-teal-900 uppercase tracking-tight">
                {headerConfig.scheduleTitle}
              </h2>
              <p className="text-gray-500 text-sm mt-1 uppercase font-bold tracking-widest opacity-60">Cập nhật lịch tập Ciputra Club</p>
            </div>

            {isMobile ? (
              <div className="flex flex-col gap-4">
                <DateStrip selected={selectedDayIndex} onSelect={setSelectedDayIndex} />
                <ScheduleList dayIndex={selectedDayIndex} schedule={schedule} user={currentUser} onUpdate={handleUpdateSchedule} />
              </div>
            ) : (
              <ScheduleGrid schedule={schedule} user={currentUser} onUpdate={handleUpdateSchedule} onNotify={addNotification} />
            )}
          </div>

          <aside className="lg:col-span-4 xl:col-span-3 space-y-6">
            <NotificationList notifications={notifications} />
            {isMobile && !showAdmin && <PWAInstaller />}
          </aside>
        </div>

        {showAdmin && (currentUser?.role === 'ADMIN' || currentUser?.role === 'MANAGER') && (
          <div className="fixed inset-0 z-[100] animate-fade">
             <AdminPanel 
              user={currentUser} 
              headerConfig={headerConfig} 
              onUpdateHeader={handleUpdateHeader} 
              permissions={permissions}
              onUpdatePermissions={(p) => { setPermissions(p); localStorage.setItem('gx_permissions_v7', JSON.stringify(p)); }}
              rootEmail={ROOT_ADMIN_EMAIL}
              onClose={() => setShowAdmin(false)}
              registeredUsers={userRegistry}
              schedule={schedule}
              onUpdateSchedule={handleUpdateSchedule}
              onNotify={addNotification}
            />
          </div>
        )}

        <footer className="mt-20 px-4 pb-12 text-center text-gray-400 text-[10px] sm:text-xs">
          <p>© 2026 Ciputra Club Fitness. Quản lý bởi Fitness Department.</p>
        </footer>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Role, User, ClassSession, HeaderConfig, PermissionRecord, AppNotification } from './types';
import Header from './components/Header';
import ScheduleGrid from './components/ScheduleGrid';
import ScheduleList from './components/ScheduleList';
import DateStrip from './components/DateStrip';
import AdminPanel from './components/AdminPanel';
import PWAInstaller from './components/PWAInstaller';
import NotificationList from './components/NotificationList';

const ROOT_ADMIN_EMAIL = 'admin@ciputraclub.vn'; 
// THAY ĐỔI URL NÀY SAU KHI TRIỂN KHAI APPS SCRIPT
const GAS_WEBAPP_URL = 'https://script.google.com/macros/s/YOUR_DEPLOYMENT_ID/exec';

const DEFAULT_HEADER: HeaderConfig = {
  logo: 'https://ciputraclub.vn/wp-content/uploads/2018/06/logo-ciputra-club.png',
  address: 'Xuan Dinh, Bac Tu Liem, Hanoi',
  hotline: '0243 743 0666',
  website: 'www.ciputraclub.vn',
  scheduleTitle: `Lịch GX - THÁNG ${new Date().getMonth() + 1} NĂM ${new Date().getFullYear()}`
};

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [schedule, setSchedule] = useState<ClassSession[]>([]);
  const [headerConfig, setHeaderConfig] = useState<HeaderConfig>(DEFAULT_HEADER);
  const [permissions, setPermissions] = useState<PermissionRecord[]>([]);
  const [notifications, setNotifications] = useState<AppNotification[]>([]);
  const [showAdmin, setShowAdmin] = useState(false);
  const [userRegistry, setUserRegistry] = useState<User[]>([]);
  const [selectedDayIndex, setSelectedDayIndex] = useState(new Date().getDay() === 0 ? 6 : new Date().getDay() - 1);
  const [isMobile, setIsMobile] = useState(window.innerWidth < 1024);
  const [isLoading, setIsLoading] = useState(true);

  // Hàm gọi API đồng bộ dữ liệu từ Google Sheets
  const syncFromCloud = async () => {
    if (GAS_WEBAPP_URL.includes('YOUR_DEPLOYMENT_ID')) {
      // Fallback nếu chưa có URL thực tế
      loadFromLocalStorage();
      setIsLoading(false);
      return;
    }

    try {
      const response = await fetch(`${GAS_WEBAPP_URL}?action=getData`);
      const data = await response.json();

      if (data.schedule) setSchedule(data.schedule);
      if (data.header) setHeaderConfig(data.header);
      if (data.users) setUserRegistry(data.users);
      if (data.notifications) setNotifications(data.notifications);
      if (data.permissions) setPermissions(data.permissions);

      setIsLoading(false);
    } catch (error) {
      console.error("Lỗi đồng bộ từ Cloud:", error);
      loadFromLocalStorage();
      setIsLoading(false);
    }
  };

  const loadFromLocalStorage = () => {
    const savedSchedule = localStorage.getItem('gx_schedule_v7');
    const savedPerms = localStorage.getItem('gx_permissions_v7');
    const savedHeader = localStorage.getItem('gx_header_v7');
    const savedRegistry = localStorage.getItem('gx_user_registry_v7');
    const savedNotifs = localStorage.getItem('gx_notifications_v7');

    if (savedSchedule) setSchedule(JSON.parse(savedSchedule));
    if (savedHeader) setHeaderConfig(JSON.parse(savedHeader));
    if (savedRegistry) setUserRegistry(JSON.parse(savedRegistry));
    if (savedNotifs) setNotifications(JSON.parse(savedNotifs));
    if (savedPerms) setPermissions(JSON.parse(savedPerms));
  };

  useEffect(() => {
    const handleResize = () => setIsMobile(window.innerWidth < 1024);
    window.addEventListener('resize', handleResize);

    syncFromCloud();

    // Tự động làm mới mỗi 2 phút để cập nhật thông báo/lịch mới nhất
    const interval = setInterval(syncFromCloud, 120000);

    return () => {
      window.removeEventListener('resize', handleResize);
      clearInterval(interval);
    };
  }, []);

  const postToCloud = async (action: string, payload: any) => {
    if (GAS_WEBAPP_URL.includes('YOUR_DEPLOYMENT_ID')) return;
    try {
      await fetch(GAS_WEBAPP_URL, {
        method: 'POST',
        mode: 'no-cors', // Apps Script yêu cầu no-cors hoặc xử lý OPTIONS
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action, data: payload })
      });
    } catch (error) {
      console.error(`Lỗi gửi dữ liệu [${action}]:`, error);
    }
  };

  const handleUpdateSchedule = (newSchedule: ClassSession[]) => {
    setSchedule(newSchedule);
    localStorage.setItem('gx_schedule_v7', JSON.stringify(newSchedule));
    postToCloud('updateSchedule', newSchedule);
  };

  const handleUpdateHeader = (newHeader: HeaderConfig) => {
    setHeaderConfig(newHeader);
    localStorage.setItem('gx_header_v7', JSON.stringify(newHeader));
    postToCloud('updateHeader', newHeader);
  };

  const addNotification = (message: string, type: 'INFO' | 'ALERT' = 'INFO') => {
    const newNotif: AppNotification = {
      id: Date.now().toString(),
      message,
      timestamp: new Date().toISOString(),
      type,
      sender: currentUser?.name || 'Hệ thống'
    };
    const updated = [newNotif, ...notifications].slice(0, 20);
    setNotifications(updated);
    localStorage.setItem('gx_notifications_v7', JSON.stringify(updated));
    postToCloud('addNotification', newNotif);
  };

  const handleGoogleLogin = (email: string, name: string, photo: string) => {
    const lowerEmail = email.toLowerCase();
    let role: Role = 'USER';

    if (lowerEmail === ROOT_ADMIN_EMAIL) {
      role = 'ADMIN';
    } else {
      const userPerm = permissions.find(p => p.email.toLowerCase() === lowerEmail);
      if (userPerm) role = userPerm.role;
    }

    const newUser: User = { id: btoa(lowerEmail), name, email: lowerEmail, role, avatar: photo };
    setCurrentUser(newUser);

    // Lưu User vào registry và Cloud
    const exists = userRegistry.find(u => u.email === lowerEmail);
    if (!exists) {
      const updatedRegistry = [...userRegistry, newUser];
      setUserRegistry(updatedRegistry);
      localStorage.setItem('gx_user_registry_v7', JSON.stringify(updatedRegistry));
      postToCloud('loginUser', newUser);
    }
  };

  if (isLoading) {
    return (
      <div className="min-h-screen bg-teal-900 flex flex-col items-center justify-center text-white">
        <div className="w-20 h-20 border-4 border-teal-400 border-t-transparent rounded-full animate-spin mb-4"></div>
        <p className="font-black uppercase tracking-[0.3em] text-[10px] animate-pulse">Đang kết nối cơ sở dữ liệu Cloud...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header 
        config={headerConfig} 
        user={currentUser} 
        onGoogleLogin={handleGoogleLogin}
        onLogout={() => { setCurrentUser(null); setShowAdmin(false); }} 
        onToggleAdmin={() => setShowAdmin(!showAdmin)}
      />

      <main className="flex-1 max-w-[1440px] mx-auto w-full px-0 sm:px-4 py-4 lg:py-8 pb-12">
        <div className="grid lg:grid-cols-12 gap-8 px-4 lg:px-0">

          <div className="lg:col-span-8 xl:col-span-9">
            <div className="mb-8 text-center lg:text-left flex flex-col lg:flex-row lg:items-end lg:justify-between gap-4">
              <div>
                <h2 className="text-2xl lg:text-4xl font-black text-teal-900 uppercase tracking-tight">
                  {headerConfig.scheduleTitle}
                </h2>
                <p className="text-gray-500 text-sm mt-1 uppercase font-bold tracking-widest opacity-60">Dữ liệu trực tuyến từ Ciputra Club</p>
              </div>
              <button 
                onClick={syncFromCloud}
                className="self-center lg:self-auto bg-white border border-slate-200 p-3 rounded-2xl hover:bg-slate-50 transition-all shadow-sm flex items-center gap-2 group"
              >
                <svg className="w-4 h-4 text-teal-600 group-active:rotate-180 transition-transform duration-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
                <span className="text-[10px] font-black uppercase text-slate-500">Làm mới</span>
              </button>
            </div>

            {isMobile ? (
              <div className="flex flex-col gap-4">
                <DateStrip selected={selectedDayIndex} onSelect={setSelectedDayIndex} />
                <ScheduleList dayIndex={selectedDayIndex} schedule={schedule} user={currentUser} onUpdate={handleUpdateSchedule} />
              </div>
            ) : (
              <ScheduleGrid schedule={schedule} user={currentUser} onUpdate={handleUpdateSchedule} onNotify={addNotification} />
            )}
          </div>

          <aside className="lg:col-span-4 xl:col-span-3 space-y-6">
            <NotificationList notifications={notifications} />
            {isMobile && !showAdmin && <PWAInstaller />}
          </aside>
        </div>

        {showAdmin && (currentUser?.role === 'ADMIN' || currentUser?.role === 'MANAGER') && (
          <div className="fixed inset-0 z-[100] animate-fade">
             <AdminPanel 
              user={currentUser} 
              headerConfig={headerConfig} 
              onUpdateHeader={handleUpdateHeader} 
              permissions={permissions}
              onUpdatePermissions={(p) => { setPermissions(p); localStorage.setItem('gx_permissions_v7', JSON.stringify(p)); postToCloud('updatePermissions', p); }}
              rootEmail={ROOT_ADMIN_EMAIL}
              onClose={() => setShowAdmin(false)}
              registeredUsers={userRegistry}
              schedule={schedule}
              onUpdateSchedule={handleUpdateSchedule}
              onNotify={addNotification}
            />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

