function doGet(e) {
  const action = e.parameter.action;
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  if (action === 'getData') {
    const result = {
      schedule: getSheetData(ss.getSheetByName('Schedule')),
      users: getSheetData(ss.getSheetByName('Users')),
      header: getSheetData(ss.getSheetByName('Header'))[0] || null,
      notifications: getSheetData(ss.getSheetByName('Notifications')),
      permissions: getSheetData(ss.getSheetByName('Permissions'))
    };
    return ContentService.createTextOutput(JSON.stringify(result)).setMimeType(ContentService.MimeType.JSON);
  }
}

function doPost(e) {
  const postData = JSON.parse(e.postData.contents);
  const action = postData.action;
  const data = postData.data;
  const ss = SpreadsheetApp.getActiveSpreadsheet();

  if (action === 'updateSchedule') {
    saveToSheet(ss.getSheetByName('Schedule'), data);
  } else if (action === 'updateHeader') {
    saveToSheet(ss.getSheetByName('Header'), [data]);
  } else if (action === 'loginUser') {
    appendUniqueUser(ss.getSheetByName('Users'), data);
  } else if (action === 'addNotification') {
    const sheet = ss.getSheetByName('Notifications');
    sheet.insertRowAfter(1);
    sheet.getRange(2, 1, 1, 1).setValue(JSON.stringify(data));
    // Giữ lại 50 thông báo gần nhất
    if (sheet.getLastRow() > 51) sheet.deleteRow(51);
  } else if (action === 'updatePermissions') {
    saveToSheet(ss.getSheetByName('Permissions'), data);
  }

  return ContentService.createTextOutput("OK").setMimeType(ContentService.MimeType.TEXT);
}

function getSheetData(sheet) {
  if (!sheet) return [];
  const rows = sheet.getDataRange().getValues();
  if (rows.length <= 1) return [];
  return rows.slice(1).map(row => JSON.parse(row[0]));
}

function saveToSheet(sheet, dataArray) {
  if (!sheet) return;
  sheet.clear();
  sheet.appendRow(["JSON_DATA"]);
  dataArray.forEach(item => {
    sheet.appendRow([JSON.stringify(item)]);
  });
}

function appendUniqueUser(sheet, user) {
  const data = getSheetData(sheet);
  const exists = data.some(u => u.email === user.email);
  if (!exists) {
    sheet.appendRow([JSON.stringify(user)]);
  }
}
